def to_float(value: Any):
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def normalize_list(value: Any) -> List[str]:
    if value is None:
        return []
    if isinstance(value, list):
        return [str(v).strip() for v in value if str(v).strip()]
    if isinstance(value, str):
        if "," in value:
            return [v.strip() for v in value.split(",") if v.strip()]
        value = value.strip()
        return [value] if value else []
    return [str(value).strip()]


def build_search_query(params: Dict[str, Any]) -> Tuple[str, List[Any]]:
    select_clause = f"""
        SELECT
            id,
            name,
            description,
            category,
            brand,
            price,
            currency,
            stock_quantity,
            rating,
            is_active,
            created_at,
            updated_at
        FROM {TABLE_NAME}
    """

    where_clauses = []
    values: List[Any] = []

    keyword = params.get("q") or params.get("keyword") or params.get("search")
    if keyword:
        where_clauses.append("(name LIKE %s OR description LIKE %s OR brand LIKE %s OR category LIKE %s)")
        like_value = f"%{keyword.strip()}%"
        values.extend([like_value, like_value, like_value, like_value])

    product_id = params.get("id")
    if product_id:
        where_clauses.append("id = %s")
        values.append(product_id)

    categories = normalize_list(params.get("category"))
    if categories:
        placeholders = ", ".join(["%s"] * len(categories))
        where_clauses.append(f"category IN ({placeholders})")
        values.extend(categories)

    brands = normalize_list(params.get("brand"))
    if brands:
        placeholders = ", ".join(["%s"] * len(brands))
        where_clauses.append(f"brand IN ({placeholders})")
        values.extend(brands)

    min_price = to_float(params.get("min_price"))
    if min_price is not None:
        where_clauses.append("price >= %s")
        values.append(min_price)

    max_price = to_float(params.get("max_price"))
    if max_price is not None:
        where_clauses.append("price <= %s")
        values.append(max_price)

    min_rating = to_float(params.get("min_rating"))
